// Chat Trigger sends the user message in chatInput
const input = $('Chat Trigger').item.json;
const prompt =
  input.chatInput ||
  input.message ||
  input['What do you want to see?'] ||
  input.prompt ||
  '';
if (!prompt) throw new Error('Prompt is empty.');
return [{ json: { prompt } }];

const prompt = $json.prompt || '';

// ── Rule 1: Minimum length ───────────────────────────────
if (prompt.trim().length < 3) {
  return [{ json: { valid: false, reason: 'Prompt is too short. Please type at least 3 characters.' } }];
}

// ── Rule 2: Block non-ASCII scripts (non-English) ────────
const nonAscii = (prompt.match(/[^\x00-\x7F]/g) || []).length;
if (nonAscii / prompt.length > 0.3) {
  return [{ json: { valid: false, reason: 'Please enter your prompt in English only.' } }];
}

// ── Rule 3: Block pure numbers / symbols ─────────────────
if (!/[a-zA-Z]/.test(prompt)) {
  return [{ json: { valid: false, reason: 'Please use actual words to describe what you want to see.' } }];
}

// ── Rule 4: Gibberish detection ──────────────────────────
const RARE_PAIRS = new Set([
  'hg','fj','jf','jk','kj','kh','hk','hj','jh',
  'xk','kx','xz','zx','vx','xv','bz','zb','qz','zq',
  'qx','xq','gj','jg','fk','kf','vb','bv','fd','df',
  'gf','fg','hf','fh','kd','dk','lk','kl','pk','kp'
]);

function isGibberishWord(word) {
  const letters = word.toLowerCase().replace(/[^a-z]/g, '');
  if (letters.length < 4) return false;

  // Signal 1: very low vowel ratio (y counts)
  const vowels = (letters.match(/[aeiouy]/g) || []).length;
  if (vowels / letters.length < 0.15) return true;

  // Signal 2: long consonant cluster (>5 in a row)
  const clusters = letters.split(/[aeiouy]+/).filter(Boolean);
  if (clusters.some(c => c.length > 5)) return true;

  // Signal 3: rare/impossible letter pair
  for (let i = 0; i < letters.length - 1; i++) {
    if (letters.length >= 6 && RARE_PAIRS.has(letters.slice(i, i + 2))) return true;
  }

  // Signal 4: 4+ same character repeated in a row (aaaa, zzzz)
  if (/(..)\1{3,}/.test(letters) || /([a-z])\1{3,}/.test(letters)) return true;

  // Signal 5: repeating 2-char pattern (hahaha, ababab)
  if (/(.{2})\1{2,}/.test(letters)) return true;

  return false;
}

const words = prompt.trim().split(/\s+/);
const checked = words.filter(w => w.replace(/[^a-zA-Z]/g, '').length >= 4);
const gibberish = checked.filter(w => isGibberishWord(w));

if (checked.length > 0 && gibberish.length / checked.length > 0.4) {
  return [{ json: { valid: false, reason: 'Your prompt looks like gibberish. Please describe what you want to see in plain English.' } }];
}

// ── Rule 5: Max length ───────────────────────────────────
if (prompt.length > 500) {
  return [{ json: { valid: false, reason: 'Prompt is too long. Please keep it under 500 characters.' } }];
}

// ✅ All checks passed
return [{ json: { valid: true, reason: '', prompt } }];

const item = $input.item;
const json = item.json || {};
const statusCode = json.statusCode ?? 0;
return [{ json: { ...json, statusCode }, binary: item.binary }];
